+    // Handle implicit string concatenation: "a" "b" -> "ab"
+    while (true) {
+        var lookahead: usize = 0;
+        while (self.current + lookahead < self.tokens.len and
+            self.tokens[self.current + lookahead].type == .Newline)
+        {
+            lookahead += 1;
+        }
